    8     private final ScheduledExecutorService executor;
    9     private final long intervalMs;
   10
   11     // 业务层只管声明：我需要一个“能调度任务的东西”
   12     public SlaveHeartbeatScheduler(ScheduledExecutorService executor, long intervalMs) {
   13         this.executor = executor;
   14         this.intervalMs = intervalMs;
   15     }
   16
   17     public void start() {
   18         executor.scheduleAtFixedRate(this::sendHeartbeat, 0, intervalMs, TimeUnit.MILLISECONDS);
   19     }
   20
   21     private void sendHeartbeat() {
   22         // 业务逻辑...
   23     }
   24 }

  2. read-infrastructure 侧：准备资源

  这里负责生产具体的“零件”。


    1 // 位置：read-infrastructure 模块
    2 package com.bitark.infrastructure.thread;
    3
    4 @Component
    5 public class ThreadPoolManager {
    6     // 这里管理着真实的线程池资源
    7     private final ScheduledExecutorService heartbeatPool = ...;
    8
    9     public ScheduledExecutorService getHeartbeatPool() {
   10         return this.heartbeatPool;
   11     }
   12 }

  3. read-adapter 侧：完成“介入” (装配)

  这是最关键的一步。adapter 模块依赖了 engine 和 infrastructure，它就像一个“红娘”，把两边撮合在一起。


    1 // 位置：read-adapter 模块
    2 package com.bitark.adapter.config;
    3
    4 @Configuration
    5 public class EngineWiringConfig {
    6
    7     @Bean
    8     public SlaveHeartbeatScheduler slaveHeartbeatScheduler(
    9             ThreadPoolManager threadPoolManager, // 来自 infra
   10             @Value("${heartbeat.interval:5000}") long interval // 来自配置
   11     ) {
   12         // 在这里，adapter 介入并完成了“连接”
   13         // 它从 threadPoolManager 拿到了真实的线程池，塞给了 engine 的类
   14         return new SlaveHeartbeatScheduler(
   15             threadPoolManager.getHeartbeatPool(),
   16             interval
   17         );
   18     }
   19 }

  ---

  这样做的三个核心好处（回答你的“为什么要这样”）：


   1. Engine 彻底解耦：
      如果你要在单元测试里测试 SlaveHeartbeatScheduler 的逻辑，你根本不需要启动 ThreadPoolManager。你只需要在测试代码里 new
  SlaveHeartbeatScheduler(Executors.newSingleThreadScheduledExecutor(), 5000) 即可。
   2. 业务与资源分离：
      engine 里的业务逻辑关心的是“心跳频率是多少”（业务参数）。
      infrastructure 里的逻辑关心的是“这个线程池的名字叫 heartbeat-pool-thread-1，核心线程数是 1”（系统资源参数）。
      这两者互不干扰。
   3. 单向依赖，避免循环：
      如果 engine 引用了 infrastructure，而 infrastructure 有时为了实现某些功能又不得不引用 common 或
  engine（比如某些业务异常的处理），极容易造成 循环依赖。现在这种 adapter -> engine/infrastructure 的结构是绝对安全的。

  总结你该怎么做：


   1. 清理 `read-engine`：删除所有对 ThreadPoolManager 或 ThreadUtils 的引用。
   2. 修改构造函数：让 engine 中需要线程池的类，在构造函数里接收 ScheduledExecutorService 或 ExecutorService 接口。
   3. 在 `read-adapter` 中装配：利用 Spring 的 @Bean 方法，从 ThreadPoolManager 取得实例并 new 出 engine 的对象。


  这样，你的 `engine` 就像一个不需要关心电源来自哪里的“电器”，只要符合插座接口（Java Executor 接口），它就能跑起来。而 `infrastructure`
  就是那个“发电机”。


